functions.routine_definition:
BEGIN
  -- Si es un INSERT
  IF (TG_OP = 'INSERT') THEN
    UPDATE ingredientes
    SET stock_actual = stock_actual + NEW.kilos
    WHERE id = NEW.ingrediente_id;

  -- Si es un DELETE
  ELSIF (TG_OP = 'DELETE') THEN
    UPDATE ingredientes
    SET stock_actual = stock_actual - OLD.kilos
    WHERE id = OLD.ingrediente_id;

  -- Si es un UPDATE
  ELSIF (TG_OP = 'UPDATE') THEN
    -- Si cambió el ingrediente_id, actualizar ambos
    IF (NEW.ingrediente_id <> OLD.ingrediente_id) THEN
      UPDATE ingredientes
      SET stock_actual = stock_actual - OLD.kilos
      WHERE id = OLD.ingrediente_id;

      UPDATE ingredientes
      SET stock_actual = stock_actual + NEW.kilos
      WHERE id = NEW.ingrediente_id;
    ELSE
      -- Si es el mismo ingrediente, solo ajustar la diferencia
      UPDATE ingredientes
      SET stock_actual = stock_actual + (NEW.kilos - OLD.kilos)
      WHERE id = NEW.ingrediente_id;
    END IF;
  END IF;

  RETURN NULL;
END;
